public class TestRunner {
    static int passed = 0;
    static int failed = 0;

    public static void main(String[] args) {

        // ══════════════ PlayerCharacter ══════════════
        try {
            PlayerCharacter pc = new PlayerCharacter("Woody", 0, 0, 3);
            check("PC.getName()", "Woody", pc.getName());
        } catch (Exception e) { fail("PC.getName()", e); }

        try {
            PlayerCharacter pc = new PlayerCharacter("Woody", 2, 5, 3);
            check("PC.getPosition()", "(2, 5)", pc.getPosition());
        } catch (Exception e) { fail("PC.getPosition()", e); }

        try {
            PlayerCharacter pc = new PlayerCharacter("Woody", 0, 0, 3);
            pc.move(4, 7);
            check("PC.move(4,7)", "(4, 7)", pc.getPosition());
        } catch (Exception e) { fail("PC.move()", e); }

        try {
            PlayerCharacter pc = new PlayerCharacter("Buzz", 1, 2, 5);
            check("PC.draw()",
                  "[Player Buzz at (1, 2)]", pc.draw());
        } catch (Exception e) { fail("PC.draw()", e); }

        try {
            PlayerCharacter pc = new PlayerCharacter("Woody", 0, 0, 3);
            pc.update();
            check("PC.update() moves right by speed",
                  "(3, 0)", pc.getPosition());
        } catch (Exception e) { fail("PC.update()", e); }

        try {
            PlayerCharacter pc = new PlayerCharacter("Woody", 0, 0, 3);
            pc.update();
            pc.update();
            check("PC.update() twice",
                  "(6, 0)", pc.getPosition());
        } catch (Exception e) { fail("PC.update() twice", e); }

        try {
            PlayerCharacter pc = new PlayerCharacter("Woody", 0, 0, 3);
            check("PC.getSpeed()", "3", String.valueOf(pc.getSpeed()));
        } catch (Exception e) { fail("PC.getSpeed()", e); }

        // ══════════════ Obstacle ══════════════
        try {
            Obstacle ob = new Obstacle("Cactus", 10, 5);
            check("Obstacle.draw()",
                  "[Obstacle Cactus at (10, 5)]", ob.draw());
        } catch (Exception e) { fail("Obstacle.draw()", e); }

        try {
            Obstacle ob = new Obstacle("Cactus", 10, 5);
            ob.update();
            check("Obstacle.update() does nothing",
                  "(10, 5)", ob.getPosition());
        } catch (Exception e) { fail("Obstacle.update()", e); }

        try {
            Obstacle ob = new Obstacle("Rock", 7, 3);
            check("Obstacle is NOT Movable",
                  "false", String.valueOf(ob instanceof Movable));
        } catch (Exception e) { fail("Obstacle instanceof check", e); }

        // ══════════════ PowerUp ══════════════
        try {
            PowerUp pu = new PowerUp("Star", 5, 10, "invincibility");
            check("PowerUp.getPosition()", "(5, 10)", pu.getPosition());
        } catch (Exception e) { fail("PowerUp.getPosition()", e); }

        try {
            PowerUp pu = new PowerUp("Star", 5, 10, "invincibility");
            check("PowerUp.draw()",
                  "[PowerUp Star (invincibility) at (5, 10)]", pu.draw());
        } catch (Exception e) { fail("PowerUp.draw()", e); }

        try {
            PowerUp pu = new PowerUp("Star", 5, 10, "invincibility");
            pu.update();
            check("PowerUp.update() floats up",
                  "(5, 9)", pu.getPosition());
        } catch (Exception e) { fail("PowerUp.update()", e); }

        try {
            PowerUp pu = new PowerUp("Star", 5, 10, "invincibility");
            pu.move(3, -2);
            check("PowerUp.move(3,-2)",
                  "(8, 8)", pu.getPosition());
        } catch (Exception e) { fail("PowerUp.move()", e); }

        try {
            PowerUp pu = new PowerUp("Star", 5, 10, "invincibility");
            check("PowerUp.getEffect()", "invincibility", pu.getEffect());
        } catch (Exception e) { fail("PowerUp.getEffect()", e); }

        // ══════════════ Interface checks ══════════════
        try {
            PlayerCharacter pc = new PlayerCharacter("W", 0, 0, 1);
            boolean m = pc instanceof Movable;
            boolean d = pc instanceof Drawable;
            boolean g = pc instanceof GameObject;
            check("PC implements Movable & Drawable, extends GameObject",
                  "true", String.valueOf(m && d && g));
        } catch (Exception e) { fail("PC interface check", e); }

        try {
            PowerUp pu = new PowerUp("S", 0, 0, "x");
            boolean m = pu instanceof Movable;
            boolean d = pu instanceof Drawable;
            check("PowerUp implements Movable & Drawable",
                  "true", String.valueOf(m && d));
        } catch (Exception e) { fail("PowerUp interface check", e); }

        try {
            Obstacle ob = new Obstacle("X", 0, 0);
            boolean d = ob instanceof Drawable;
            boolean m = ob instanceof Movable;
            check("Obstacle is Drawable but NOT Movable",
                  "true", String.valueOf(d && !m));
        } catch (Exception e) { fail("Obstacle interface check", e); }

        // ══════════════ GameEngine.runGameLoop ══════════════
        try {
            GameObject[] objs = {
                new PlayerCharacter("Woody", 0, 0, 2),
                new Obstacle("Rock", 5, 5),
                new PowerUp("Star", 3, 8, "speed")
            };
            String result = GameEngine.runGameLoop(objs, 1);
            boolean hasTick   = result.contains("=== Tick 1 ===");
            boolean hasSummary = result.contains("Done: 2 movable, 3 drawable, 3 total");
            check("runGameLoop — tick header & summary",
                  "true", String.valueOf(hasTick && hasSummary));
        } catch (Exception e) { fail("runGameLoop tick & summary", e); }

        // After 1 tick: Woody at (2,0), Star at (3,7)
        try {
            GameObject[] objs = {
                new PlayerCharacter("Woody", 0, 0, 2),
                new Obstacle("Rock", 5, 5),
                new PowerUp("Star", 3, 8, "speed")
            };
            String result = GameEngine.runGameLoop(objs, 1);
            boolean woodyPos = result.contains("Woody") && result.contains("(2, 0)");
            boolean starPos  = result.contains("Star") && result.contains("(3, 7)");
            check("runGameLoop — positions after 1 tick",
                  "true", String.valueOf(woodyPos && starPos));
        } catch (Exception e) { fail("runGameLoop positions", e); }

        // After 2 ticks: Woody at (4,0), Star at (3,6)
        try {
            GameObject[] objs = {
                new PlayerCharacter("Woody", 0, 0, 2),
                new PowerUp("Star", 3, 8, "speed")
            };
            String result = GameEngine.runGameLoop(objs, 2);
            boolean tick2 = result.contains("=== Tick 2 ===");
            boolean woodyFinal = result.contains("(4, 0)");
            boolean starFinal  = result.contains("(3, 6)");
            check("runGameLoop — 2 ticks: positions correct",
                  "true", String.valueOf(tick2 && woodyFinal && starFinal));
        } catch (Exception e) { fail("runGameLoop 2 ticks", e); }

        try {
            GameObject[] objs = {
                new Obstacle("Rock", 5, 5)
            };
            String result = GameEngine.runGameLoop(objs, 1);
            boolean summary = result.contains("Done: 0 movable, 1 drawable, 1 total");
            check("runGameLoop — obstacle only: 0 movable",
                  "true", String.valueOf(summary));
        } catch (Exception e) { fail("runGameLoop obstacle only", e); }

        // ══════════════ Encapsulation ══════════════
        try {
            java.lang.reflect.Field f = PlayerCharacter.class.getDeclaredField("x");
            check("PC.x is private", "true",
                  String.valueOf(java.lang.reflect.Modifier.isPrivate(f.getModifiers())));
        } catch (NoSuchFieldException e) {
            fail("PC.x field exists", new Exception("Field 'x' not found"));
        } catch (Exception e) { fail("PC.x is private", e); }

        try {
            java.lang.reflect.Field f = PowerUp.class.getDeclaredField("effect");
            check("PowerUp.effect is private", "true",
                  String.valueOf(java.lang.reflect.Modifier.isPrivate(f.getModifiers())));
        } catch (NoSuchFieldException e) {
            fail("PowerUp.effect field exists", new Exception("Field 'effect' not found"));
        } catch (Exception e) { fail("PowerUp.effect is private", e); }
    }

    // ── Helpers ──
    static void check(String label, String expected, String actual) {
        if (expected.equals(actual)) {
            System.out.println("PASS: " + label); passed++;
        } else {
            System.out.println("FAIL: " + label
                + " — expected \"" + expected
                + "\" but got \"" + actual + "\""); failed++;
        }
    }
    static void fail(String label, Exception e) {
        System.out.println("FAIL: " + label + " — " + e.getMessage()); failed++;
    }
}
